static void
hostbase_open(const char *base)
{

	if (hostbase_fd != -1)
		close(hostbase_fd);
	hostbase_fd = open(base, O_DIRECTORY | O_PATH);
	if (hostbase_fd == -1)
		err(EX_OSERR, "open");
}

